#include "driver/gpio.h"
#include "esp_timer.h"

#include "basissoftware/feedback.h"
#include "user_project/project_config.h"

namespace {
constexpr const char *TAG = "buttonLesson";
constexpr gpio_num_t BUTTON_PIN = GPIO_NUM_0;
constexpr int BUTTON_PRESSED_LEVEL = 0;
constexpr int64_t DEBOUNCE_US = 50000;

bool wasPressed = false;
int64_t lastChangeUs = 0;

void reportButtonPressed() {
  feedbackInfo(TAG, "Tastendruck erkannt: taste_gedrueckt (Projekt %s)", GERNETIX_PROJECT_ID);
}
}

extern "C" void userMain() {
  gpio_config_t buttonConfig = {};
  buttonConfig.pin_bit_mask = 1ULL << BUTTON_PIN;
  buttonConfig.mode = GPIO_MODE_INPUT;
  buttonConfig.pull_up_en = GPIO_PULLUP_ENABLE;
  buttonConfig.pull_down_en = GPIO_PULLDOWN_DISABLE;
  buttonConfig.intr_type = GPIO_INTR_DISABLE;
  gpio_config(&buttonConfig);

  wasPressed = gpio_get_level(BUTTON_PIN) == BUTTON_PRESSED_LEVEL;
  feedbackInfo(TAG, "Taster-Lektion bereit: GPIO 0 mit internem Pull-up");
}

extern "C" void userTick() {
  const bool isPressed = gpio_get_level(BUTTON_PIN) == BUTTON_PRESSED_LEVEL;
  const int64_t nowUs = esp_timer_get_time();
  if (isPressed && !wasPressed && nowUs - lastChangeUs >= DEBOUNCE_US) {
    lastChangeUs = nowUs;
    reportButtonPressed();
  }
  wasPressed = isPressed;
}

#pragma once

// This value is created when the account-bound learning project is created.
#define GERNETIX_PROJECT_ID "__PROJECT_ID__"
